                    <div className="mt-6 flex justify-end space-x-2">
                        <Button type="button" variant="ghost" onClick={handleCloseFeedback}>Cancel</Button>
                        <Button type="submit" isLoading={isLoading} disabled={rating === 0 || isLoading}>Submit</Button>
                    </div>
                </form>
            )}
        </Modal>
        </>
    );
};

