const AdminStats: React.FC<{ tickets: SupportTicket[] }> = ({ tickets }) => {
    const stats = useMemo(() => ({
        open: tickets.filter(t => t.status === 'Open' || t.status === 'In Progress').length,
        resolved: tickets.filter(t => t.status === 'Resolved' || t.status === 'Closed').length,
        highPriority: tickets.filter(t => t.priority === 'High' || t.priority === 'Urgent').length,
    }), [tickets]);

    return (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
            <StatCard title="Total Tickets" metric={tickets.length.toString()} iconName="fas fa-ticket-alt" iconColor="text-blue-500" />
            <StatCard title="Open" metric={stats.open.toString()} iconName="fas fa-envelope-open" iconColor="text-yellow-500" />
            <StatCard title="Resolved" metric={stats.resolved.toString()} iconName="fas fa-check-circle" iconColor="text-green-500" />
            <StatCard title="Critical" metric={stats.highPriority.toString()} iconName="fas fa-exclamation-triangle" iconColor="text-red-500" />
        </div>
    );
};


export const SupportPage: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();

    const [tickets, setTickets] = useState<SupportTicket[]>(mockSupportTickets);
    const [isViewModalOpen, setIsViewModalOpen] = useState(false);
    const [selectedTicket, setSelectedTicket] = useState<SupportTicket | null>(null);
    const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
    const [isKbModalOpen, setIsKbModalOpen] = useState(false);
    const [isFilterPanelOpen, setIsFilterPanelOpen] = useState(false);
    const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
    const [ticketToAssign, setTicketToAssign] = useState<SupportTicket | null>(null);

    const [currentPage, setCurrentPage] = useState(1);
    const [rowsPerPage, setRowsPerPage] = useState(10);
    const [openMenuId, setOpenMenuId] = useState<string | null>(null);
    const kebabMenuRef = useRef<HTMLDivElement>(null);

    const viewAsUserId = searchParams.get('viewAsUser');
    const isAdmin = user?.role === 'admin';
    const isElevated = (user?.role === 'admin' || user?.role === 'reseller') && !viewAsUserId;

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (kebabMenuRef.current && !kebabMenuRef.current.contains(event.target as Node)) {
                setOpenMenuId(null);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, []);

    const [filters, setFilters] = useState<SupportFilters>({
        customerId: '',
        ticketId: '',
        subject: '',
        status: 'all',
        severity: 'all',
        type: 'all',
        dateFrom: '',
        dateTo: '',
    });

    const allCustomers = useMemo(() => getAllMockCustomers(), []);
    const internalStaff = useMemo(() => getAllMockInternalUsers(), []);

    const customerOptions = useMemo(() => 
        allCustomers.map(c => ({ value: c.id, label: `${c.fullName} (${c.companyName})` })),
        [allCustomers]
    );

    const staffOptions = useMemo(() => 
        internalStaff.map(s => ({ value: s.id, label: s.fullName })),
        [internalStaff]
    );

    const filteredTickets = useMemo(() => {
        return tickets.filter(ticket => {
            // Context Restriction: If impersonating or a regular customer, strictly limit to that specific customer.
            if (viewAsUserId && ticket.customerId !== viewAsUserId) return false;
            if (!isElevated && !viewAsUserId && ticket.customerId !== user?.id) return false;

            // Application Filtering:
            if (isElevated && filters.customerId && ticket.customerId !== filters.customerId) {
                return false;
            }
            if (filters.status !== 'all' && ticket.status !== filters.status) {
                return false;
            }
            if (filters.ticketId && !ticket.id.toLowerCase().includes(filters.ticketId.toLowerCase())) {
                return false;
            }
            if (filters.subject && !ticket.subject.toLowerCase().includes(filters.subject.toLowerCase())) {
                return false;
            }
            if (filters.severity !== 'all' && ticket.priority !== filters.severity) {
                return false;
            }
            if (filters.type !== 'all' && ticket.requestType !== filters.type) {
                return false;
            }

            const ticketDate = new Date(ticket.lastUpdate);
            if (filters.dateFrom && ticketDate < new Date(filters.dateFrom)) {
                return false;
            }
            if (filters.dateTo) {
                const toDate = new Date(filters.dateTo);
                toDate.setHours(23, 59, 59, 999);
                if (ticketDate > toDate) {
                    return false;
                }
            }
            return true;
        });
    }, [tickets, filters, isElevated, viewAsUserId, user?.id]);

    useEffect(() => {
        setCurrentPage(1);
    }, [filteredTickets]);

    const paginatedTickets = useMemo(() => {
        const startIndex = (currentPage - 1) * rowsPerPage;
        return filteredTickets.slice(startIndex, startIndex + rowsPerPage);
    }, [filteredTickets, currentPage, rowsPerPage]);

    const activeFilterCount = useMemo(() => {
        return Object.values(filters).filter(value => {
            if (typeof value === 'string') return value !== '' && value !== 'all';
            return false;
        }).length;
    }, [filters]);


    const handleApplyFilters = (newFilters: SupportFilters) => {
        setFilters(newFilters);
    };

    const handleApplyCustomerFilters = (newFilters: CustomerSupportFilters) => {
        setFilters(prev => ({ 
            ...prev, 
            ...newFilters, 
            customerId: '' 
        }));
    };

    const clearFilters = () => {
        setFilters({
            customerId: '',
            ticketId: '',
            subject: '',
            status: 'all',
            severity: 'all',
            type: 'all',
            dateFrom: '',
            dateTo: '',
        });
    };

    const handleViewTicket = (ticketId: string) => {
        const ticket = tickets.find(t => t.id === ticketId);
        if (ticket) {
            setSelectedTicket(ticket);
            setIsViewModalOpen(true);
        }
    };

    const handleCloseTicket = (ticketId: string) => {
        if (window.confirm(`Are you sure you want to close ticket ${ticketId}?`)) {
            setTickets(prev => prev.map(t => 
                t.id === ticketId 
                    ? { ...t, status: 'Closed', lastUpdate: new Date().toISOString() } 
                    : t
            ));
        }
    };

    const handleUpdateTicket = (updatedTicket: SupportTicket) => {
        setTickets(prev => prev.map(t => t.id === updatedTicket.id ? updatedTicket : t));
    };

    const handleOpenKbModal = () => {
        setIsKbModalOpen(true);
    };

    const handleProceedToCreateTicket = () => {
        setIsKbModalOpen(false);
        if (user?.role === 'admin') {
            navigate('/app/admin/support/create');
        } else {
            setIsCreateModalOpen(true);
        }
    };

    const handleCreateTicketSubmit = (newTicketData: Omit<SupportTicket, 'id' | 'status' | 'lastUpdate' | 'customerId' | 'customerName' | 'comments' | 'internalComments'>) => {
        const newTicket: SupportTicket = {
            id: `TKT-${Math.floor(Math.random() * 90000) + 10000}`,
            status: 'Open',
            lastUpdate: new Date().toISOString(),
            customerName: user?.fullName || 'Customer',
            customerId: user?.id || '',
            ...newTicketData,
        };
        setTickets(prev => [newTicket, ...prev]);
        setIsCreateModalOpen(false);
    };

    const handleAssignTicket = (adminId: string, adminName: string) => {
        if (ticketToAssign) {
            setTickets(prev => prev.map(t => 
                t.id === ticketToAssign.id 
                    ? { ...t, assignedAdminId: adminId, assignedAdminName: adminName, lastUpdate: new Date().toISOString() } 
                    : t
            ));
            setIsAssignModalOpen(false);
            setTicketToAssign(null);
        }
    };

    const handlePickupTicket = (ticketId: string) => {
        if (user) {
            setTickets(prev => prev.map(t => 
                t.id === ticketId 
                    ? { ...t, assignedAdminId: user.id, assignedAdminName: user.fullName, lastUpdate: new Date().toISOString() } 
                    : t
            ));
        }
    };

    return (
        <>
            {isElevated && <AdminStats tickets={filteredTickets} />}
            <Card title={isElevated ? "Support Center Administration" : "Support Center"} titleActions={
                <div className="flex items-center gap-2">
                    <Button
                        variant="outline"
                        onClick={() => setIsFilterPanelOpen(true)}
                        leftIconName="fas fa-filter"
                        className="relative"
                    >
                        Filters
                        {activeFilterCount > 0 && (
                            <span className="absolute -top-1 -right-1 flex justify-center items-center h-4 w-4 rounded-full bg-red-500 text-white text-xs font-semibold">
                                {activeFilterCount}
                            </span>
                        )}
                    </Button>
                    <Button onClick={handleOpenKbModal} leftIconName="fas fa-plus-circle">
                        Create New Ticket
                    </Button>
                </div>
            }>
                <div className="overflow-x-auto border dark:border-gray-700 rounded-lg">
                    <table className="min-w-full bg-white dark:bg-slate-800">
                        <thead className="bg-gray-50 dark:bg-slate-700">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Ticket ID</th>
                                {isElevated && (
                                    <>
                                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Customer</th>
                                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Reseller</th>
                                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Assign To</th>
                                    </>
                                )}
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Subject</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Product</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Status</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Priority</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">Last Update</th>
                                <th className="relative px-6 py-3"><span className="sr-only">Actions</span></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                            {paginatedTickets.map(ticket => (
                                <tr key={ticket.id}>
