                    <FormField as="select" id="type-filter" name="type" label="Type" value={localFilters.type} onChange={handleLocalChange}>
                        <option value="all">All Types</option>
                        <option value="Inquiry">Inquiry</option>
                        <option value="Issue">Issue</option>
                        <option value="Task">Task</option>
                        <option value="Feature Request">Feature Request</option>
                    </FormField>
                    <div className="grid grid-cols-2 gap-4">
                        <FormField id="dateFrom-filter" name="dateFrom" label="From" type="date" value={localFilters.dateFrom} onChange={handleLocalChange} />
                        <FormField id="dateTo-filter" name="dateTo" label="To" type="date" value={localFilters.dateTo} onChange={handleLocalChange} />
                    </div>
                </div>

                <div className="flex-shrink-0 p-4 border-t border-gray-200 dark:border-slate-700 bg-white dark:bg-slate-800 space-x-2 flex justify-end">
                    <Button variant="outline" onClick={handleClear}>Clear Filters</Button>
                    <Button onClick={handleApply}>Apply Filters</Button>
                </div>
            </div>
        </>
    );
};

const AssignTicketModal: React.FC<{
    isOpen: boolean;
    onClose: () => void;
    onAssign: (adminId: string, adminName: string) => void;
    staffOptions: { value: string; label: string }[];
}> = ({ isOpen, onClose, onAssign, staffOptions }) => {
    const [selectedAdminId, setSelectedAdminId] = useState('');

    const handleAssign = () => {
        const admin = staffOptions.find(opt => opt.value === selectedAdminId);
        if (admin) {
            onAssign(admin.value, admin.label);
        }
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Assign Ticket to Staff" size="md">
            <div className="space-y-4 min-h-[350px]">
                <SearchableSelect
                    id="admin-assignment"
                    label="Internal Staff Member"
                    options={staffOptions}
                    value={selectedAdminId}
                    onChange={setSelectedAdminId}
                    placeholder="Select an admin or reseller..."
                    listHeight="max-h-72"
                />
                <div className="flex justify-end gap-2 pt-4 border-t dark:border-gray-700 absolute bottom-4 right-4 left-4">
                    <Button variant="ghost" onClick={onClose}>Cancel</Button>
                    <Button onClick={handleAssign} disabled={!selectedAdminId}>Assign Staff</Button>
                </div>
            </div>
        </Modal>
    );
};

const AdminStats: React.FC<{ tickets: SupportTicket[] }> = ({ tickets }) => {
    const stats = useMemo(() => ({
        open: tickets.filter(t => t.status === 'Open' || t.status === 'In Progress').length,
        resolved: tickets.filter(t => t.status === 'Resolved' || t.status === 'Closed').length,
        highPriority: tickets.filter(t => t.priority === 'High' || t.priority === 'Urgent').length,
    }), [tickets]);

    return (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
            <StatCard title="Total Tickets" metric={tickets.length.toString()} iconName="fas fa-ticket-alt" iconColor="text-blue-500" />
            <StatCard title="Open" metric={stats.open.toString()} iconName="fas fa-envelope-open" iconColor="text-yellow-500" />
            <StatCard title="Resolved" metric={stats.resolved.toString()} iconName="fas fa-check-circle" iconColor="text-green-500" />
            <StatCard title="Critical" metric={stats.highPriority.toString()} iconName="fas fa-exclamation-triangle" iconColor="text-red-500" />
        </div>
    );
};


export const SupportPage: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();

    const [tickets, setTickets] = useState<SupportTicket[]>(mockSupportTickets);
    const [isViewModalOpen, setIsViewModalOpen] = useState(false);
    const [selectedTicket, setSelectedTicket] = useState<SupportTicket | null>(null);
    const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
    const [isKbModalOpen, setIsKbModalOpen] = useState(false);
    const [isFilterPanelOpen, setIsFilterPanelOpen] = useState(false);
    const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
    const [ticketToAssign, setTicketToAssign] = useState<SupportTicket | null>(null);

    const [currentPage, setCurrentPage] = useState(1);
    const [rowsPerPage, setRowsPerPage] = useState(10);
    const [openMenuId, setOpenMenuId] = useState<string | null>(null);
    const kebabMenuRef = useRef<HTMLDivElement>(null);

    // Sorting State
    const [sortConfig, setSortConfig] = useState<{ key: keyof SupportTicket | 'customer' | 'reseller' | null; direction: 'asc' | 'desc' }>({ key: 'lastUpdate', direction: 'desc' });

    const viewAsUserId = searchParams.get('viewAsUser');
    const isAdmin = user?.role === 'admin';
    const isElevated = (user?.role === 'admin' || user?.role === 'reseller') && !viewAsUserId;

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (kebabMenuRef.current && !kebabMenuRef.current.contains(event.target as Node)) {
                setOpenMenuId(null);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, []);

    const [filters, setFilters] = useState<SupportFilters>({
        customerId: '',
        ticketId: '',
        subject: '',
        status: 'all',
        severity: 'all',
        type: 'all',
        dateFrom: '',
        dateTo: '',
    });

    const allCustomers = useMemo(() => getAllMockCustomers(), []);
    const internalStaff = useMemo(() => getAllMockInternalUsers(), []);

    const customerOptions = useMemo(() => 
        allCustomers.map(c => ({ value: c.id, label: `${c.fullName} (${c.companyName})` })),
        [allCustomers]
    );

    const staffOptions = useMemo(() => 
        internalStaff.map(s => ({ value: s.id, label: s.fullName })),
        [internalStaff]
    );

    const handleSort = (key: keyof SupportTicket | 'customer' | 'reseller') => {
        setSortConfig(prev => ({
            key,
            direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const renderSortIcon = (key: string) => {
        if (sortConfig.key !== key) return <Icon name="fas fa-sort" className="ml-1 opacity-20" />;
        return <Icon name={sortConfig.direction === 'asc' ? "fas fa-sort-up" : "fas fa-sort-down"} className="ml-1 text-[#679a41] dark:text-emerald-400" />;
    };

    const filteredTickets = useMemo(() => {
        let result = tickets.filter(ticket => {
            // Context Restriction
            if (viewAsUserId && ticket.customerId !== viewAsUserId) return false;
            if (!isElevated && !viewAsUserId && ticket.customerId !== user?.id) return false;

            // Application Filtering
            if (isElevated && filters.customerId && ticket.customerId !== filters.customerId) return false;
            if (filters.status !== 'all' && ticket.status !== filters.status) return false;
            if (filters.ticketId && !ticket.id.toLowerCase().includes(filters.ticketId.toLowerCase())) return false;
            if (filters.subject && !ticket.subject.toLowerCase().includes(filters.subject.toLowerCase())) return false;
            if (filters.severity !== 'all' && ticket.priority !== filters.severity) return false;
            if (filters.type !== 'all' && ticket.requestType !== filters.type) return false;

            const ticketDate = new Date(ticket.lastUpdate);
            if (filters.dateFrom && ticketDate < new Date(filters.dateFrom)) return false;
            if (filters.dateTo) {
                const toDate = new Date(filters.dateTo);
                toDate.setHours(23, 59, 59, 999);
                if (ticketDate > toDate) return false;
            }
            return true;
        });

        // Sorting Logic
        if (sortConfig.key) {
            result.sort((a, b) => {
                let valA: any = a[sortConfig.key as keyof SupportTicket] || '';
                let valB: any = b[sortConfig.key as keyof SupportTicket] || '';

                // Handle special weight-based sorting
                if (sortConfig.key === 'priority') {
                    valA = PRIORITY_WEIGHT[a.priority] || 0;
                    valB = PRIORITY_WEIGHT[b.priority] || 0;
                } else if (sortConfig.key === 'status') {
                    valA = STATUS_WEIGHT[a.status] || 0;
                    valB = STATUS_WEIGHT[b.status] || 0;
                } else if (sortConfig.key === 'customer') {
                    valA = a.customerName || '';
                    valB = b.customerName || '';
                } else if (sortConfig.key === 'reseller') {
                    // Assuming resellerName is part of the ticket or can be fetched
                    valA = (a as any).resellerName || '';
                    valB = (b as any).resellerName || '';
                }

                if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
                if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
                return 0;
            });
        }

        return result;
    }, [tickets, filters, isElevated, viewAsUserId, user?.id, sortConfig]);

    useEffect(() => {
        setCurrentPage(1);
    }, [filteredTickets]);

    const paginatedTickets = useMemo(() => {
        const startIndex = (currentPage - 1) * rowsPerPage;
