                        Filters
                        {activeFilterCount > 0 && (
                            <span className="absolute -top-1 -right-1 flex justify-center items-center h-4 w-4 rounded-full bg-red-500 text-white text-xs font-semibold">
                                {activeFilterCount}
                            </span>
                        )}
                    </Button>
                    <Button onClick={handleOpenKbModal} leftIconName="fas fa-plus-circle">
                        Create New Ticket
                    </Button>
                </div>
            }>
                <div className="overflow-x-auto border dark:border-gray-700 rounded-lg">
                    <table className="min-w-full bg-white dark:bg-slate-800">
                        <thead className="bg-gray-50 dark:bg-slate-700">
                            <tr>
                                <th onClick={() => handleSort('id')} className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-600 transition-colors group">
                                    Ticket ID {renderSortIcon('id')}
                                </th>
                                {isElevated && (
                                    <>
                                        <th onClick={() => handleSort('customer')} className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-600 transition-colors group">
                                            Customer {renderSortIcon('customer')}
                                        </th>
                                        <th onClick={() => handleSort('reseller')} className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-600 transition-colors group">
                                            Reseller {renderSortIcon('reseller')}
                                        </th>
                                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">
                                            Assign To
                                        </th>
                                    </>
